def _gcs_bucket_to_nested(gcs_bucket: GCSBucket) -> GCSBucketNested:
    """Convert flat GCSBucket to nested format."""
    attrs = GCSBucketAttributes()
    _populate_gcs_bucket_attrs(attrs, gcs_bucket)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        gcs_bucket, _GCS_BUCKET_REL_FIELDS, GCSBucketRelationshipAttributes
    )
    return GCSBucketNested(
        guid=gcs_bucket.guid,
        type_name=gcs_bucket.type_name,
        status=gcs_bucket.status,
        version=gcs_bucket.version,
        create_time=gcs_bucket.create_time,
        update_time=gcs_bucket.update_time,
        created_by=gcs_bucket.created_by,
        updated_by=gcs_bucket.updated_by,
        classifications=gcs_bucket.classifications,
        classification_names=gcs_bucket.classification_names,
        meanings=gcs_bucket.meanings,
        labels=gcs_bucket.labels,
        business_attributes=gcs_bucket.business_attributes,
        custom_attributes=gcs_bucket.custom_attributes,
        pending_tasks=gcs_bucket.pending_tasks,
        proxy=gcs_bucket.proxy,
        is_incomplete=gcs_bucket.is_incomplete,
        provenance_type=gcs_bucket.provenance_type,
        home_id=gcs_bucket.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _gcs_bucket_from_nested(nested: GCSBucketNested) -> GCSBucket:
    """Convert nested format to flat GCSBucket."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else GCSBucketAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _GCS_BUCKET_REL_FIELDS,
        GCSBucketRelationshipAttributes,
    )
    return GCSBucket(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_gcs_bucket_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _gcs_bucket_to_nested_bytes(gcs_bucket: GCSBucket, serde: Serde) -> bytes:
    """Convert flat GCSBucket to nested JSON bytes."""
    return serde.encode(_gcs_bucket_to_nested(gcs_bucket))


def _gcs_bucket_from_nested_bytes(data: bytes, serde: Serde) -> GCSBucket:
    """Convert nested JSON bytes to flat GCSBucket."""
    nested = serde.decode(data, GCSBucketNested)
    return _gcs_bucket_from_nested(nested)


